#include "interface.h"

#include <simdjson.h>

uint64_t compute_checksum(const std::string& json_input) {
  simdjson::ondemand::parser parser;
  simdjson::padded_string padded(json_input);
  simdjson::ondemand::document doc = parser.iterate(padded);

  uint64_t sum = 0;
  for (auto item : doc.get_array()) {
    simdjson::ondemand::object obj = item.get_object();
    for (auto field : obj) {
      std::string_view key = field.unescaped_key();
      if (key == "id") {
        sum += field.value().get_uint64().value();
      } else if (key == "x") {
        sum += field.value().get_uint64().value();
      } else if (key == "vals") {
        simdjson::ondemand::array vals = field.value().get_array();
        size_t idx = 0;
        for (auto v : vals) {
          if (idx == 1) {
            sum += v.get_uint64().value();
            break;
          }
          ++idx;
        }
      }
    }
  }
  return sum;
}
